const bin=$input.item.binary||{};
const b=bin.data; if(!b) throw new Error('no pdf');
const buf=await this.helpers.getBinaryDataBuffer(0,'data');
const docs=[{type:'document',source:{type:'base64',media_type:'application/pdf',data:buf.toString('base64')}}];
const textBody='\u0410\u0432\u0442\u043e: \u0424\u04211234 / \u0412\u04225678\n\u0414\u0430\u0442\u0430: 14.07.2026\n\u041f\u0435\u0440\u0435\u0432\u0456\u0437\u043d\u0438\u043a: MULTYTRANS LLC\n\u041f\u0435\u0440\u0435\u0442\u0438\u043d: Dorokhusk - Yahodyn';
function field(label){const re=new RegExp(label+'\\s*[:\uFF1A]\\s*(.+)','i');const m=textBody.match(re);return m?m[1].trim():'';}
let truck='',trailer='';const av=field('\u0410\u0432\u0442\u043e');if(av){const p=av.split('/');truck=(p[0]||'').trim();trailer=(p[1]||'').trim();}
const date=field('\u0414\u0430\u0442\u0430');const border=field('\u041f\u0435\u0440\u0435\u0442\u0438\u043d');const carrier=field('\u041f\u0435\u0440\u0435\u0432\u0456\u0437\u043d\u0438\u043a');
const prompt="Ти обробляєш комерційні документи. ВИКОРИСТОВУЙ ЛИШЕ Bill of Lading та Commercial Invoice. Поверни СТРОГО валідний JSON без markdown: {\"sender\":\"відправник назва+адреса, кожна частина з нового рядка через \\\\n\",\"receiver\":\"отримувач так само через \\\\n\",\"delivery_city\":\"місто отримувача\",\"delivery_country\":\"країна отримувача\",\"loading\":\"порт прибуття МІСТО, КРАЇНА\",\"invoice\":\"номер інвойсу\",\"invoice_date\":\"дата інвойсу ДД.ММ.РРРР\",\"container\":\"номер контейнера\",\"packages\":\"к-сть місць число\",\"packaging\":\"упаковка\",\"goods\":\"назва вантажу\",\"weight\":\"вага брутто з одиницею\",\"volume\":\"об єм\"}. Якщо нема — \"\".";
const body={model:'claude-sonnet-4-6',max_tokens:1500,messages:[{role:'user',content:docs.concat([{type:'text',text:prompt}])}]};
return [{json:{body,truck,trailer,date,border,carrier}}];

const resp=$input.item.json;
let text=(resp.content&&Array.isArray(resp.content))?resp.content.map(c=>c.text||'').join(''):(resp.text||'').toString();
text=text.replace(/```json/gi,'').replace(/```/g,'').trim();
let data={};try{data=JSON.parse(text);}catch(e){const mm=text.match(/\{[\s\S]*\}/);if(mm)data=JSON.parse(mm[0]);}
const prep=$('prep').item.json;const f=k=>(data[k]||'').toString().trim();
const container=f('container');const receiver=f('receiver');
const docTitle='CMR draft \u2116'+container+' '+receiver.split(/[\n,]/)[0].trim()+' (TEST)';
const map={sender:f('sender'),receiver:receiver,delivery_city:f('delivery_city'),delivery_country:f('delivery_country'),loading:f('loading'),invoice:f('invoice'),invoice_date:f('invoice_date'),container:container,packages:f('packages'),packaging:f('packaging'),goods:f('goods'),weight:f('weight'),volume:f('volume'),date:prep.date||'',border:prep.border||'',carrier:prep.carrier||'',truck:prep.truck||'',trailer:prep.trailer||''};
const ph=Object.keys(map).map(k=>['{'+'{'+k+'}'+'}',map[k]]);
const docsBody={requests:ph.map(p=>({replaceAllText:{containsText:{text:p[0],matchCase:true},replaceText:String(p[1]||'')}}))};
return [{json:Object.assign({},map,{docTitle,docsBody})}];
